import os
import io
import csv
import numpy as np
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import pandas as pd
from PIL import Image
import pickle
from datetime import datetime

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
MODEL_FOLDER = 'models'
DATA_FOLDER = 'training_data'

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_FOLDER, exist_ok=True)
os.makedirs(DATA_FOLDER, exist_ok=True)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 100 * 1024 * 1024

IMAGE_SIZE = (224, 224)
NUM_CLASSES = 10
BATCH_SIZE = 32
EPOCHS = 10

global_model = None
training_data = []
training_labels = []

def create_model(num_classes=NUM_CLASSES):
    model = keras.Sequential([
        layers.Input(shape=(224, 224, 3)),
        layers.Conv2D(32, (3, 3), activation='relu'),
        layers.MaxPooling2D((2, 2)),
        layers.Conv2D(64, (3, 3), activation='relu'),
        layers.MaxPooling2D((2, 2)),
        layers.Conv2D(128, (3, 3), activation='relu'),
        layers.MaxPooling2D((2, 2)),
        layers.Flatten(),
        layers.Dense(128, activation='relu'),
        layers.Dropout(0.5),
        layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(
        optimizer='adam',
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )
    
    return model

def load_model():
    global global_model
    model_path = os.path.join(MODEL_FOLDER, 'latest_model.h5')
    if os.path.exists(model_path):
        global_model = keras.models.load_model(model_path)
    else:
        global_model = create_model()
    return global_model

def save_model(model):
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    model_path = os.path.join(MODEL_FOLDER, f'model_{timestamp}.h5')
    model.save(model_path)
    
    latest_path = os.path.join(MODEL_FOLDER, 'latest_model.h5')
    model.save(latest_path)

def preprocess_image(image_data):
    img = Image.open(io.BytesIO(image_data))
    img = img.convert('RGB')
    img = img.resize(IMAGE_SIZE)
    img_array = np.array(img) / 255.0
    return img_array

def load_csv_data(csv_path):
    df = pd.read_csv(csv_path)
    return df

@app.route('/upload_csv', methods=['POST'])
def upload_csv():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if not file.filename.endswith('.csv'):
        return jsonify({'error': 'File must be CSV format'}), 400
    
    filename = secure_filename(file.filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    file.save(filepath)
    
    try:
        df = load_csv_data(filepath)
        
        data_save_path = os.path.join(DATA_FOLDER, f'data_{datetime.now().strftime("%Y%m%d_%H%M%S")}.csv')
        df.to_csv(data_save_path, index=False)
        
        return jsonify({
            'message': 'CSV uploaded successfully',
            'rows': len(df),
            'columns': list(df.columns)
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/upload_image', methods=['POST'])
def upload_image():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    if 'label' not in request.form:
        return jsonify({'error': 'No label provided'}), 400
    
    image_file = request.files['image']
    label = int(request.form['label'])
    
    if label < 0 or label >= NUM_CLASSES:
        return jsonify({'error': f'Label must be between 0 and {NUM_CLASSES-1}'}), 400
    
    try:
        image_data = image_file.read()
        img_array = preprocess_image(image_data)
        
        training_data.append(img_array)
        training_labels.append(label)
        
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        image_filename = f'img_{timestamp}_{label}.jpg'
        image_path = os.path.join(DATA_FOLDER, image_filename)
        
        with open(image_path, 'wb') as f:
            f.write(image_data)
        
        return jsonify({
            'message': 'Image uploaded successfully',
            'label': label,
            'total_samples': len(training_data)
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/contribute_batch', methods=['POST'])
def contribute_batch():
    if 'images' not in request.files:
        return jsonify({'error': 'No images provided'}), 400
    
    images = request.files.getlist('images')
    labels_str = request.form.get('labels', '')
    
    try:
        labels = [int(l) for l in labels_str.split(',')]
        
        if len(images) != len(labels):
            return jsonify({'error': 'Number of images and labels must match'}), 400
        
        uploaded_count = 0
        for image_file, label in zip(images, labels):
            if label < 0 or label >= NUM_CLASSES:
                continue
            
            image_data = image_file.read()
            img_array = preprocess_image(image_data)
            
            training_data.append(img_array)
            training_labels.append(label)
            
            timestamp = datetime.now().strftime('%Y%m%d_%H%M%S_%f')
            image_filename = f'img_{timestamp}_{label}.jpg'
            image_path = os.path.join(DATA_FOLDER, image_filename)
            
            with open(image_path, 'wb') as f:
                f.write(image_data)
            
            uploaded_count += 1
        
        return jsonify({
            'message': 'Batch uploaded successfully',
            'uploaded': uploaded_count,
            'total_samples': len(training_data)
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/train', methods=['POST'])
def train_model():
    global global_model, training_data, training_labels
    
    if len(training_data) == 0:
        return jsonify({'error': 'No training data available'}), 400
    
    try:
        params = request.get_json() or {}
        epochs = params.get('epochs', EPOCHS)
        batch_size = params.get('batch_size', BATCH_SIZE)
        
        X_train = np.array(training_data)
        y_train = np.array(training_labels)
        
        if global_model is None:
            global_model = load_model()
        
        history = global_model.fit(
            X_train, y_train,
            epochs=epochs,
            batch_size=batch_size,
            validation_split=0.2,
            verbose=1
        )
        
        save_model(global_model)
        
        return jsonify({
            'message': 'Model trained successfully',
            'samples': len(X_train),
            'epochs': epochs,
            'final_accuracy': float(history.history['accuracy'][-1]),
            'final_loss': float(history.history['loss'][-1])
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/train_from_csv', methods=['POST'])
def train_from_csv():
    global global_model
    
    if 'file' not in request.files:
        return jsonify({'error': 'No CSV file provided'}), 400
    
    file = request.files['file']
    
    try:
        df = pd.read_csv(file)
        
        if 'image_path' not in df.columns or 'label' not in df.columns:
            return jsonify({'error': 'CSV must contain image_path and label columns'}), 400
        
        images = []
        labels = []
        
        for _, row in df.iterrows():
            img_path = row['image_path']
            label = int(row['label'])
            
            if os.path.exists(img_path):
                with open(img_path, 'rb') as f:
                    img_data = f.read()
                img_array = preprocess_image(img_data)
                images.append(img_array)
                labels.append(label)
        
        if len(images) == 0:
            return jsonify({'error': 'No valid images found'}), 400
        
        X_train = np.array(images)
        y_train = np.array(labels)
        
        if global_model is None:
            global_model = load_model()
        
        history = global_model.fit(
            X_train, y_train,
            epochs=EPOCHS,
            batch_size=BATCH_SIZE,
            validation_split=0.2
        )
        
        save_model(global_model)
        
        return jsonify({
            'message': 'Model trained from CSV successfully',
            'samples': len(X_train),
            'final_accuracy': float(history.history['accuracy'][-1])
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/predict', methods=['POST'])
def predict():
    global global_model
    
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    try:
        if global_model is None:
            global_model = load_model()
        
        image_file = request.files['image']
        image_data = image_file.read()
        img_array = preprocess_image(image_data)
        img_array = np.expand_dims(img_array, axis=0)
        
        predictions = global_model.predict(img_array)
        predicted_class = int(np.argmax(predictions[0]))
        confidence = float(predictions[0][predicted_class])
        
        return jsonify({
            'predicted_class': predicted_class,
            'confidence': confidence,
            'all_probabilities': predictions[0].tolist()
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/model_info', methods=['GET'])
def model_info():
    global global_model
    
    if global_model is None:
        global_model = load_model()
    
    return jsonify({
        'total_training_samples': len(training_data),
        'num_classes': NUM_CLASSES,
        'image_size': IMAGE_SIZE,
        'model_loaded': global_model is not None
    }), 200

@app.route('/clear_training_data', methods=['POST'])
def clear_training_data():
    global training_data, training_labels
    
    training_data = []
    training_labels = []
    
    return jsonify({'message': 'Training data cleared'}), 200

if __name__ == '__main__':
    load_model()
    app.run(host='0.0.0.0', port=5000, debug=True)